long long solve(long long n, vector<vector<long long>> edges, string label) {
    // Build adjacency list
    vector<vector<long long>> adj(n);
    for (auto& edge : edges) {
        adj[edge[0]].push_back(edge[1]);
        adj[edge[1]].push_back(edge[0]);
    }

    // DFS to find the longest palindrome path
    vector<vector<long long>> visited(n, vector<long long>(n, 0));
    long long max_len = 0;

    function<void(long long, long long, vector<long long>&, long long)> dfs = [&](long long node, long long prev, vector<long long>& path, long long current_len) {
        // Mark current node as visited
        for (int i = 0; i < n; ++i) {
            visited[i][node] = 1;
        }

        // Check if current path can form a palindrome
        bool is_palindrome = true;
        for (int i = 0; i < current_len / 2; ++i) {
            if (label[path[i]] != label[path[current_len - 1 - i]]) {
                is_palindrome = false;
                break;
            }
        }

        if (is_palindrome) {
            max_len = max(max_len, current_len);
        }

        // Explore neighbors
        for (long long neighbor : adj[node]) {
            if (neighbor == prev) continue;
            if (visited[neighbor][node] == 0) {
                path.push_back(neighbor);
                dfs(neighbor, node, path, current_len + 1);
                path.pop_back();
            }
        }

        // Unmark current node as visited
        for (int i = 0; i < n; ++i) {
            visited[i][node] = 0;
        }
    };

    // Start DFS from each node
    for (long long start = 0; start < n; ++start) {
        vector<long long> path;
        path.push_back(start);
        dfs(start, -1, path, 1);
    }

    return max_len;
