        // Explore neighbors
        for (long long neighbor : adj[node]) {
            if (neighbor == prev) continue;
            if (visited[neighbor][node] == 0) {
                path.push_back(neighbor);
                dfs(neighbor, node, path, current_len + 1);
                path.pop_back();
            }
        }

        // Unmark current node as visited
        for (int i = 0; i < n; ++i) {
            visited[i][node] = 0;
